-- Insert "How to Use the Local SEO Hub" SOP (idempotent)
INSERT INTO sops (title, category, description, content)
SELECT
  'How to Use the Local SEO Hub',
  'gbp',
  'Complete guide to using the Weekly Task Board, SOP Library, task history, archiving, alerts, and all Local SEO Hub features.',
  E'# How to Use the Local SEO Hub\n\nThe **Local SEO Hub** is your central workspace for managing weekly SEO tasks, tracking progress, and accessing standard operating procedures. This guide walks you through every feature.\n\n---\n\n## Getting Started\n\n1. Navigate to **GBP Management** from the admin dashboard\n2. Click the **Local SEO Hub** tab at the top of the page\n3. You''ll see two sections: the **Weekly Task Board** (Kanban) and the **SOP Library**\n\n---\n\n## Weekly Task Board (Kanban)\n\n### Selecting a Company\n\n- Use the **company dropdown** at the top to select which client you''re working on\n- Alert indicators (red/amber dots) appear next to company names that have overdue or approaching tasks\n\n### Understanding the Columns\n\nThe task board has three columns:\n\n| Column | Meaning |\n|--------|---------|\n| **New Task** | Tasks that haven''t been started yet |\n| **In Progress** | Tasks currently being worked on |\n| **Finished** | Completed tasks |\n\n### Task Cards\n\nEach task card shows:\n- **Title** — what needs to be done\n- **Due date** — when it''s due (colour-coded: red = overdue, amber = due soon)\n- **Progress bar** — for recurring tasks (e.g. 3/4 posts created)\n\n### Moving Tasks Between Columns\n\n- **Drag and drop** a card from one column to another\n- Or click the **green tick** button to mark a task as finished\n- Click the **green tick again** on a finished task to undo and move it back\n\n### Adding a New Task\n\n1. Click the **+ Add Task** button\n2. Fill in the task title, location, due date, column and priority\n3. Click **Save**\n\n### Editing a Task\n\n1. Click on any task card to open it\n2. Update the fields as needed\n3. For recurring tasks (GBP Posts, Keywords, Photos, Reviews), you can:\n   - Track your progress count\n   - Add individual entries (URLs, keywords, etc.)\n   - Add free-form notes\n4. Click **Save Changes**\n\n### Archiving a Task\n\n- Click the **archive icon** (box with arrow) on any task card\n- Confirm the action — the task moves to the archive\n- Archived tasks are visible in the **Archived Weeks** section at the bottom\n\n### Deleting a Task\n\n- Click the **red bin** icon on a task card\n- Confirm deletion — this is permanent\n\n---\n\n## Auto-Generated Weekly Tasks\n\nThe system automatically creates recurring tasks each week for every location:\n\n| Task | Frequency | Target |\n|------|-----------|--------|\n| Add Keywords to GBP | Weekly | 10 keywords |\n| Create GBP Posts | Weekly | 3-4 posts |\n| Upload New Photos | Weekly | 1-2 photos |\n| Write New Reviews | Monthly | 2 reviews |\n\n- These appear automatically on Monday for the current week\n- Unfinished tasks from last week carry over automatically\n- Finished tasks from past weeks are auto-archived\n\n---\n\n## Task History\n\n- Click the **clock icon** next to any location header to view its task history\n- History shows all completed and archived tasks grouped by week\n- Click on any history card to **expand it** and see full details (category, priority, due date, notes)\n\n---\n\n## Alert System\n\n| Alert | Meaning |\n|-------|---------|\n| **Red triangle** | Task is overdue (past its due date and not finished) |\n| **Amber triangle** | Task is in "New" column and due within 3 days |\n\n- Alerts appear on task cards, location headers, and the company dropdown\n- "In Progress" tasks never show amber alerts — only "New" tasks do\n\n---\n\n## Archived Weeks Section\n\n1. Click **Show Archive** / **Hide Archive** toggle below the task board\n2. Browse archived tasks — filter by week using the dropdown\n3. Click any archived task card to **expand** and see full details\n4. Archive shows tasks from all previous weeks that were completed or manually archived\n\n---\n\n## SOP Library\n\n### Viewing SOPs\n\n1. Scroll down to the **SOP Library** section\n2. Click any SOP card to expand and read the full content\n3. Use the **search bar** to find SOPs by title or description\n\n### Adding a New SOP\n\n1. Click **+ Add SOP**\n2. Enter a title and short description\n3. Write the full content using **Markdown** formatting\n4. Click **Add**\n\n### Editing or Deleting SOPs\n\n- Click the **pencil icon** to edit an existing SOP\n- Click the **bin icon** to delete (this is permanent)\n\n---\n\n## Tips & Best Practices\n\n- **Check the board daily** to keep tasks moving through the columns\n- **Track your progress** by opening recurring task cards and logging entries\n- **Use notes** to record URLs, keyword lists, or any relevant details\n- **Review history** before starting a new week to see what was completed\n- **Archive manually** when you want to clear tasks early without waiting for auto-archive\n- **Refer to SOPs** for step-by-step guidance on GBP optimisation, keyword research, and AI prompts'
WHERE NOT EXISTS (
  SELECT 1 FROM sops WHERE title = 'How to Use the Local SEO Hub'
);
